def executeCommand():
    # Validate command using regex to check if it contains only valid characters (no special characters)
    import re
    pattern = r"^[a-zA-Z0-9_]+$"

    while True:
        user_input = input("Enter a command: ")

        # Check for empty inputs and exit if the command is 'exit'
        if not user_input or user_input.lower() == "exit":
            print("Exiting...")
            break

        # Validate command using regex pattern
        if re.fullmatch(pattern, user_input):
            try:
                subprocess.run(user_input, shell=True, check=True)
                print("Command executed successfully")
            except Exception as e:
                print(f"Error executing command '{user_input}': {str(e)}")
        else:
            print("Invalid command format. Please enter a valid alphanumeric command.")

